- (NSString *) stringByTrimmingTrailingCharactersInSet:(NSCharacterSet *)characterSet {
    NSRange end = [self rangeOfCharacterFromSet:[characterSet invertedSet] options:NSBackwardsSearch];

    if (end.location == NSNotFound) {
        return @"";
